changeSet.sql:
ALTER TABLE practice_finding DROP CONSTRAINT IF EXISTS chk_practice_finding_target_type;
ALTER TABLE practice_finding
ADD CONSTRAINT chk_practice_finding_target_type
CHECK (target_type IN ('PULL_REQUEST', 'ISSUE'));

changeSet.rollback:
ALTER TABLE practice_finding DROP CONSTRAINT IF EXISTS chk_practice_finding_target_type;
ALTER TABLE practice_finding
ADD CONSTRAINT chk_practice_finding_target_type
CHECK (target_type IN ('PULL_REQUEST'));

changeSet.sql:
ALTER TABLE practice_finding DROP CONSTRAINT IF EXISTS chk_practice_finding_verdict;
UPDATE practice_finding SET verdict = 'OBSERVED' WHERE verdict = 'POSITIVE';
UPDATE practice_finding SET verdict = 'NOT_OBSERVED' WHERE verdict = 'NEGATIVE';
ALTER TABLE practice_finding ADD CONSTRAINT chk_practice_finding_verdict
    CHECK (verdict IN ('OBSERVED', 'NOT_OBSERVED', 'NOT_APPLICABLE'));

changeSet.rollback:
ALTER TABLE practice_finding DROP CONSTRAINT IF EXISTS chk_practice_finding_verdict;
UPDATE practice_finding SET verdict = 'POSITIVE' WHERE verdict = 'OBSERVED';
UPDATE practice_finding SET verdict = 'NEGATIVE' WHERE verdict = 'NOT_OBSERVED';
ALTER TABLE practice_finding ADD CONSTRAINT chk_practice_finding_verdict
    CHECK (verdict IN ('POSITIVE', 'NEGATIVE', 'NOT_APPLICABLE'));

changeSet.sql:
ALTER TABLE feedback ADD CONSTRAINT chk_feedback_target_type CHECK (target_type IS NULL OR target_type IN ('PULL_REQUEST', 'ISSUE'));
ALTER TABLE feedback ADD CONSTRAINT chk_feedback_surface CHECK (surface IN ('IN_CONTEXT', 'CONVERSATION', 'REFLECTION_DASHBOARD', 'FACILITATOR'));
ALTER TABLE feedback ADD CONSTRAINT chk_feedback_state CHECK (state IN ('PREPARED', 'DELIVERED', 'SUPERSEDED', 'SUPPRESSED', 'FAILED'));
ALTER TABLE feedback ADD CONSTRAINT chk_feedback_suppression_reason CHECK (suppression_reason IS NULL OR suppression_reason IN ('AUDIENCE_REVIEWER', 'BELOW_THRESHOLD', 'LOW_CONFIDENCE', 'POLICY_FLOOR_DROP'));
ALTER TABLE feedback ADD CONSTRAINT chk_feedback_origin CHECK (origin IN ('AGENT', 'POLICY_FLOOR', 'FALLBACK'));

changeSet.rollback:
ALTER TABLE feedback DROP CONSTRAINT IF EXISTS chk_feedback_target_type;
ALTER TABLE feedback DROP CONSTRAINT IF EXISTS chk_feedback_surface;
