ALTER TABLE feedback DROP CONSTRAINT IF EXISTS chk_feedback_suppression_reason;
ALTER TABLE feedback DROP CONSTRAINT IF EXISTS chk_feedback_origin;

changeSet.sql:
ALTER TABLE feedback_placement ADD CONSTRAINT chk_feedback_placement_placement CHECK (placement IN ('SUMMARY', 'INLINE', 'CONVERSATION_TURN'));
ALTER TABLE feedback_placement ADD CONSTRAINT chk_feedback_placement_anchor_kind CHECK (anchor_kind IS NULL OR anchor_kind IN ('LINE', 'RANGE', 'FILE', 'IMAGE'));
ALTER TABLE feedback_placement ADD CONSTRAINT chk_feedback_placement_anchor_side CHECK (anchor_side IS NULL OR anchor_side IN ('OLD', 'NEW'));
ALTER TABLE feedback_placement ADD CONSTRAINT chk_feedback_placement_anchor_start_side CHECK (anchor_start_side IS NULL OR anchor_start_side IN ('OLD', 'NEW'));
ALTER TABLE feedback_placement ADD CONSTRAINT chk_feedback_placement_posted_state CHECK (posted_state IN ('PENDING', 'POSTED', 'SNAPPED', 'FELL_BACK', 'OUTDATED', 'ORPHANED', 'GONE', 'FAILED'));

