changeSet.sql:
UPDATE finding_reaction fr SET correlation_key = pf.correlation_key
FROM practice_finding pf
WHERE fr.finding_id = pf.id AND pf.correlation_key IS NOT NULL AND fr.correlation_key IS NULL;
